import{_ as o,c as r,o as n,ag as a}from"./chunks/framework.DK1-H3E1.js";const u=JSON.parse('{"title":"上下文工程：让 LLM 用好「上下文」","description":"","frontmatter":{"order":7},"headers":[],"relativePath":"ai/context-engineering.md","filePath":"ai/context-engineering.md","lastUpdated":1772197851000}'),l={name:"ai/context-engineering.md"};function i(e,t,s,g,h,d){return n(),r("div",null,t[0]||(t[0]=[a('<h1 id="上下文工程-让-llm-用好「上下文」" tabindex="-1">上下文工程：让 LLM 用好「上下文」 <a class="header-anchor" href="#上下文工程-让-llm-用好「上下文」" aria-label="Permalink to &quot;上下文工程：让 LLM 用好「上下文」&quot;">​</a></h1><blockquote><p>📅 主题：Context Engineering — 上下文设计、窗口管理与少样本</p></blockquote><h2 id="一、什么是上下文工程" tabindex="-1">一、什么是上下文工程 <a class="header-anchor" href="#一、什么是上下文工程" aria-label="Permalink to &quot;一、什么是上下文工程&quot;">​</a></h2><p><strong>上下文工程（Context Engineering）</strong> 指的是：<strong>有意识地设计、组织和管理输入给大语言模型（LLM）的整段内容</strong>，使模型在有限上下文窗口内获得最有助于完成任务的背景与指令。</p><p>和「只写好一句 Prompt」不同，上下文工程关注的是：</p><ul><li><strong>整段输入</strong>：系统提示、历史对话、文档片段、示例等如何组合</li><li><strong>上下文窗口</strong>：如何在长度限制下取舍、裁剪、排序</li><li><strong>信息密度与结构</strong>：什么该放、什么不该放、谁先谁后</li></ul><p>可以说：<strong>Prompt 工程管「说什么」，上下文工程管「整体摆什么、怎么摆」。</strong></p><hr><h2 id="二、上下文的构成" tabindex="-1">二、上下文的构成 <a class="header-anchor" href="#二、上下文的构成" aria-label="Permalink to &quot;二、上下文的构成&quot;">​</a></h2><p>一次请求里，模型看到的「上下文」通常由几部分组成（不同产品命名不一，本质类似）：</p><table tabindex="0"><thead><tr><th>部分</th><th>作用</th><th>常见内容</th></tr></thead><tbody><tr><td><strong>系统提示 / System</strong></td><td>定角色、规则、格式</td><td>身份设定、禁止事项、输出规范</td></tr><tr><td><strong>用户消息 / User</strong></td><td>当前轮次的真实请求</td><td>问题、任务描述、附加材料</td></tr><tr><td><strong>历史对话 / History</strong></td><td>多轮对话的过往内容</td><td>上一轮 Q&amp;A、澄清、修正</td></tr><tr><td><strong>检索 / 注入内容</strong></td><td>从外部注入的知识</td><td>RAG 查到的文档、数据库结果</td></tr><tr><td><strong>示例 / Few-shot</strong></td><td>输入输出样例</td><td>1～N 个 (输入, 输出) 对</td></tr><tr><td><strong>思维过程 / CoT</strong></td><td>推理步骤（若保留）</td><td>「让我们一步步思考」后的中间推理</td></tr></tbody></table><p>上下文工程要做的，就是<strong>合理设计每一块的内容与顺序</strong>，并在<strong>不超长</strong>的前提下保证关键信息不被截断。</p><hr><h2 id="三、上下文窗口与长度管理" tabindex="-1">三、上下文窗口与长度管理 <a class="header-anchor" href="#三、上下文窗口与长度管理" aria-label="Permalink to &quot;三、上下文窗口与长度管理&quot;">​</a></h2><h3 id="_3-1-上下文窗口是什么" tabindex="-1">3.1 上下文窗口是什么 <a class="header-anchor" href="#_3-1-上下文窗口是什么" aria-label="Permalink to &quot;3.1 上下文窗口是什么&quot;">​</a></h3><p><strong>上下文窗口（Context Window）</strong> 是模型单次请求能接受的最大 token 数（含输入 + 输出）。例如 8K、32K、128K、200K 等。超出部分会被截断或拒绝。</p><ul><li><strong>输入</strong>：系统提示 + 历史 + 当前用户消息 + 检索/示例等，全部算在「输入 token」里。</li><li><strong>输出</strong>：模型生成的回复单独算「输出 token」，一般也受 max_tokens 限制。</li></ul><h3 id="_3-2-长度管理原则" tabindex="-1">3.2 长度管理原则 <a class="header-anchor" href="#_3-2-长度管理原则" aria-label="Permalink to &quot;3.2 长度管理原则&quot;">​</a></h3><ol><li><p><strong>优先保证「必须有的」</strong></p><ul><li>系统提示里的硬性规则（安全、格式、角色）尽量保留。</li><li>当前用户问题与直接相关的检索片段不要裁掉。</li></ul></li><li><p><strong>历史对话可裁剪</strong></p><ul><li>保留最近几轮或与当前问题明显相关的轮次。</li><li>更早的可以总结成一小段「背景摘要」再放入，而不是全文堆叠。</li></ul></li><li><p><strong>RAG 结果要精选</strong></p><ul><li>检索 Top-K 后，可再做重排序或摘要，只把最相关的几段放进上下文，避免「塞满文档、淹没问题」。</li></ul></li><li><p><strong>示例求精不求多</strong></p><ul><li>Few-shot 示例 1～3 个往往足够；示例过长会挤占空间，且可能干扰对当前任务的关注。</li></ul></li><li><p><strong>长文档策略</strong></p><ul><li>超长文档：先分块、检索再注入，而不是整篇塞进上下文。</li><li>若必须用长上下文模型「整篇读」，可把问题放在文档之后，并明确写出「请根据上文回答」。</li></ul></li></ol><hr><h2 id="四、上下文设计实践" tabindex="-1">四、上下文设计实践 <a class="header-anchor" href="#四、上下文设计实践" aria-label="Permalink to &quot;四、上下文设计实践&quot;">​</a></h2><h3 id="_4-1-顺序与结构" tabindex="-1">4.1 顺序与结构 <a class="header-anchor" href="#_4-1-顺序与结构" aria-label="Permalink to &quot;4.1 顺序与结构&quot;">​</a></h3><p>常见且稳定的顺序是：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[系统提示] → [可选：少样本示例] → [历史对话摘要或最近几轮] → [当前轮：检索内容 + 用户问题]</span></span></code></pre></div><ul><li><strong>系统提示在前</strong>：先定调角色与规则，再给具体任务。</li><li><strong>示例紧跟系统</strong>：让模型先「学会格式/风格」，再处理真实输入。</li><li><strong>检索内容靠近问题</strong>：和当前问题相关的文档片段放在同一轮、问题附近，便于模型对齐「依据」与「问题」。</li><li><strong>历史在后或摘要</strong>：避免最早几轮把「当前轮」挤到窗口末尾（有些模型对末尾更敏感）。</li></ul><h3 id="_4-2-少样本-few-shot-在上下文中的用法" tabindex="-1">4.2 少样本（Few-shot）在上下文中的用法 <a class="header-anchor" href="#_4-2-少样本-few-shot-在上下文中的用法" aria-label="Permalink to &quot;4.2 少样本（Few-shot）在上下文中的用法&quot;">​</a></h3><p><strong>Few-shot</strong> 即在上下文中放入若干「输入→输出」示例，不更新模型参数，仅通过示例引导生成。</p><ul><li><strong>作用</strong>：规范格式、展示推理风格、约束输出结构。</li><li><strong>建议</strong>： <ul><li>示例与当前任务高度相关、格式一致。</li><li>1～3 个典型示例即可；过多会占 token 且可能过拟合到示例风格。</li><li>示例可放在系统提示后、用户问题前，便于模型「先学后做」。</li></ul></li></ul><h3 id="_4-3-思维链-chain-of-thought-与上下文" tabindex="-1">4.3 思维链（Chain-of-Thought）与上下文 <a class="header-anchor" href="#_4-3-思维链-chain-of-thought-与上下文" aria-label="Permalink to &quot;4.3 思维链（Chain-of-Thought）与上下文&quot;">​</a></h3><p><strong>思维链（CoT）</strong> 是在上下文里引导模型「先推理、再给结论」，例如：</p><ul><li>在系统或用户消息中加入：「请先一步步分析，再给出最终答案。」</li><li>在 Few-shot 示例里展示「推理过程 + 最终答案」的写法。</li></ul><p>这样，模型会倾向于在生成的<strong>前半段</strong>输出推理步骤，<strong>后半段</strong>输出答案。若你只关心答案，可解析最后一段；若需要审计或教学，可保留完整 CoT 在上下文/日志中。</p><hr><h2 id="五、与-rag、prompt-的关系" tabindex="-1">五、与 RAG、Prompt 的关系 <a class="header-anchor" href="#五、与-rag、prompt-的关系" aria-label="Permalink to &quot;五、与 RAG、Prompt 的关系&quot;">​</a></h2><ul><li><strong>RAG</strong>：负责「从外部知识库里选出该放进上下文的内容」；上下文工程负责「把这些内容放在哪、放多少、以什么形式放」。</li><li><strong>Prompt 工程</strong>：负责单条指令的表述（清晰、具体、无歧义）；上下文工程负责整段输入的布局、长度和优先级。</li></ul><p>三者配合：<strong>好的 Prompt + 合理的 RAG 检索结果 + 有意识的上下文设计</strong>，才能在高 token 成本下得到稳定、可控的生成效果。</p><hr><h2 id="六、小结-上下文工程要点" tabindex="-1">六、小结：上下文工程要点 <a class="header-anchor" href="#六、小结-上下文工程要点" aria-label="Permalink to &quot;六、小结：上下文工程要点&quot;">​</a></h2><ol><li><strong>明确「整段输入」的组成</strong>：系统、历史、检索、示例、当前问题，各占多少、谁先谁后。</li><li><strong>在窗口限制内做优先级</strong>：必保留的（系统规则、当前问题、关键检索）优先；历史与示例可裁剪或摘要。</li><li><strong>少样本求精</strong>：1～3 个高质量、同格式示例，紧接系统提示。</li><li><strong>思维链可显式要求</strong>：在系统或示例中体现「先推理再答案」，便于复杂任务。</li><li><strong>长文档用检索+注入</strong>：避免整篇塞入；检索结果精选后再放入当前轮，靠近问题。</li></ol><p>把「上下文」当作一种可设计、可迭代的工程对象，而不仅是「把能想到的都塞进去」，就是上下文工程的核心思路。</p>',40)]))}const c=o(l,[["render",i]]);export{u as __pageData,c as default};
